parameters.text:
=Generate a {{ $json.strategy_type }} strategy for {{ $json.symbol }} futures.

Constraints: {{ $json.constraints }}

Iteration: {{ $json.iteration }} of {{ $json.max_iterations }} (Stage {{ $json.stage }})
{{ $json.stage_prompt ? 'REFINEMENT DIRECTIVE: ' + $json.stage_prompt : '' }}
{{ $json.refinement_notes ? 'Previous attempt feedback: ' + $json.refinement_notes : '' }}

Output a single StrategyDSL JSON object. No code, no markdown, just the JSON.

parameters.jsCode:
const items = $input.all();
const aiOutput = items[0].json.output || items[0].json.text || '';

let parsed;
try {
  const jsonMatch = aiOutput.match(/```json?\s*([\s\S]*?)```/) ||
                    aiOutput.match(/(\{[\s\S]*\})/);
  const jsonStr = jsonMatch ? jsonMatch[1].trim() : aiOutput.trim();
  parsed = JSON.parse(jsonStr);
} catch (e) {
  return [{
    json: {
      error: true,
      message: `Failed to parse AI output: ${e.message}`,
      raw_output: aiOutput,
      iteration: $('Init Iteration Counter').first().json.iteration || 0
    }
  }];
}

const ctx = $('Init Iteration Counter').first().json || {};
const now = new Date();
const startDate = new Date(now);
startDate.setFullYear(startDate.getFullYear() - 2);

// Validate required DSL fields
const requiredFields = ['name', 'entry_indicator', 'entry_params', 'entry_type', 'exit_type'];
const missing = requiredFields.filter(f => !parsed[f]);
if (missing.length > 0) {
  return [{
    json: {
      error: true,
      message: `Missing required DSL fields: ${missing.join(', ')}`,
      raw_output: aiOutput,
      iteration: ctx.iteration || 0
    }
  }];
}

return [{
  json: {
    // DSL fields
    name: parsed.name || 'unnamed_strategy',
    description: parsed.description || '',
    symbol: parsed.symbol || ctx.symbol || 'MES',
    timeframe: parsed.timeframe || '1h',
    direction: parsed.direction || 'both',
    entry_type: parsed.entry_type || 'trend_follow',
    entry_indicator: parsed.entry_indicator || 'sma_crossover',
    entry_params: parsed.entry_params || {},
    entry_condition: parsed.entry_condition || '',
    exit_type: parsed.exit_type || 'atr_multiple',
    exit_params: parsed.exit_params || {},
    stop_loss_atr_multiple: parsed.stop_loss_atr_multiple || 2.0,
    take_profit_atr_multiple: parsed.take_profit_atr_multiple || 4.0,
    preferred_regime: parsed.preferred_regime || 'TRENDING_UP',
    session_filter: parsed.session_filter || 'RTH_ONLY',
    source: 'n8n',
    tags: parsed.tags || [],
    // Backtest config
    start_date: startDate.toISOString().split('T')[0],
    end_date: now.toISOString().split('T')[0],
    // Loop context
    iteration: ctx.iteration || 0,
    max_iterations: ctx.max_iterations || 9,
    stage: ctx.stage || 1,
    strategy_type: ctx.strategy_type || 'momentum',
    constraints: ctx.constraints || '',
    error: false
  }
}];

const backtest = $('Fetch Backtest Results').first().json;
const strategy = $('Parse AI Strategy Output').first().json;

return [{
  json: {
    success: true,
    status: 'accepted',
    strategy_name: strategy.strategy_name,
    tier: backtest.tier,
    iteration: strategy.iteration + 1,
    metrics: {
      sharpe: backtest.sharpe,
      max_drawdown: backtest.max_drawdown,
      total_return: backtest.total_return
    },
    backtest_id: backtest.id || backtest.backtestId,
    message: `Strategy '${strategy.strategy_name}' accepted with tier ${backtest.tier}`
  }
}];

// Get backtest results - try Fetch Backtest Results first, fall back to direct input
// (compilation failures route here directly with fake metrics)
let backtest;
try {
  backtest = $('Fetch Backtest Results').first().json;
} catch (e) {
  backtest = $input.first().json;
}
if (!backtest || !backtest.tier) {
  backtest = $input.first().json;
}

const strategy = $('Parse AI Strategy Output').first().json;
const initCtx = $('Init Iteration Counter').first().json;

const currentIteration = (strategy.iteration || 0) + 1;
const maxIterations = strategy.max_iterations || 9;

// Compute stage (1-3, each stage = 3 iterations)
const stage = Math.floor(currentIteration / 3) + 1;

// Stage prompts
const stagePrompts = {
  1: 'Adjust parameters within the current entry pattern. Try different period lengths, thresholds, and ATR multiples. Keep the same entry_indicator.',
  2: 'Change entry/exit logic. Try a different entry_indicator or exit_type while keeping the same general concept and symbol.',
  3: 'Pivot to a completely different concept. Try a different entry_type, direction, or regime. The current approach is not working.'
};
const stagePrompt = stagePrompts[Math.min(stage, 3)] || stagePrompts[3];

// Current attempt metrics
const currentMetrics = {
  sharpe: backtest.sharpe || 0,
  max_drawdown: backtest.max_drawdown || 0,
  win_rate: backtest.win_rate || 0,
  profit_factor: backtest.profit_factor || 0,
  total_return: backtest.total_return || 0,
  iteration: currentIteration,
  stage: stage,
  compilation_failed: backtest.status === 'compilation_failed'
};

// Accumulate attempts
const prevAttempts = initCtx.attempts || [];
const attempts = [...prevAttempts, currentMetrics];

// Track best metrics (ignore compilation failures)
const validAttempts = attempts.filter(a => !a.compilation_failed);
const bestSharpe = validAttempts.length > 0 ? Math.max(...validAttempts.map(a => a.sharpe)) : 0;
const prevBest = initCtx.best_metrics_so_far;
const bestMetrics = prevBest && prevBest.sharpe >= bestSharpe ? prevBest : currentMetrics;

// Kill signal checks
let killSignal = null;

// After stage 1 (iteration 3+): if best Sharpe < 0.8, no edge
if (currentIteration >= 3 && bestSharpe < 0.8) {
  killSignal = 'no_edge';
}

// Any iteration: catastrophic max drawdown
if (validAttempts.length > 0) {
  const worstDD = Math.max(...validAttempts.map(a => Math.abs(a.max_drawdown)));
  if (worstDD > 6000) {
    killSignal = 'catastrophic_risk';
  }
}

// All valid attempts have win rate < 0.40
if (validAttempts.length >= 3 && validAttempts.every(a => a.win_rate < 0.40)) {
  killSignal = 'wrong_direction';
}

// All valid attempts have profit factor < 1.0
if (validAttempts.length >= 3 && validAttempts.every(a => a.profit_factor < 1.0)) {
  killSignal = 'unprofitable';
}

// Flat improvement: last 3 valid attempts Sharpe improvement < 0.1
if (validAttempts.length >= 3) {
  const last3 = validAttempts.slice(-3);
  const sharpeRange = Math.max(...last3.map(a => a.sharpe)) - Math.min(...last3.map(a => a.sharpe));
  if (sharpeRange < 0.1 && bestSharpe < 1.5) {
    killSignal = 'flat_improvement';
  }
}

// Determine if we can retry
const canRetry = !killSignal && currentIteration < maxIterations;

return [{
  json: {
    can_retry: canRetry,
    kill_signal: killSignal,
    iteration: currentIteration,
    max_iterations: maxIterations,
    stage: Math.min(stage, 3),
    stage_prompt: stagePrompt,
    symbol: strategy.symbol,
    strategy_type: strategy.strategy_type,
    constraints: strategy.constraints,
    rejection_reason: killSignal
      ? `Kill signal: ${killSignal}`
      : (backtest.rejection_reason || 'Strategy did not meet tier criteria'),
    last_tier: backtest.tier,
    last_metrics: currentMetrics,
    best_metrics_so_far: bestMetrics,
    attempts: attempts
  }
}];

